import { Component, h, Prop, Element, Listen, State, Event, EventEmitter } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { generateRandId } from '../../utils/utils';
import { NavItemSelectableDetail } from '../wdpr-nav-item-selectable/wdpr-nav-item-selectable.model';

@Component({
  tag: 'wdpr-secondary-nav-section',
  shadow: true,
})
export class WdprSecondaryNavSection {
  @Element() el: HTMLWdprSecondaryNavSectionElement;

  @State() private _internalId: string;
  @State() private _hasLabelSlot: boolean = false;

  @Prop({ mutable: true, reflect: true }) sectionId: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = '';
  @Prop() variant: 'loud' | 'quiet' = 'quiet';

  @Event() wdprSecondaryNavSectionClick: EventEmitter<string>;

  componentWillLoad() {
    this._internalId = this.sectionId || `wdpr-secondary-nav-section-${generateRandId()}`;
    this._updateSlots();
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  @Listen('wdprNavItemSmallClick')
  handleNavItemSmallClick(event: CustomEvent<string>) {
    if (!event?.detail) return;
    this.wdprSecondaryNavSectionClick.emit(event.detail);
  }

  @Listen('wdprSelectChange')
  handleNavItemSelectableChange(event: CustomEvent<NavItemSelectableDetail>) {
    const itemId = event?.detail?.itemId;
    if (!itemId) return;
    this.wdprSecondaryNavSectionClick.emit(itemId);
  }

  private _updateSlots = () => {
    this._hasLabelSlot = !!this.el.querySelector('[slot="label"]');
  };

  private get _labelClass(): string {
    return this.variant === 'loud'
      ? 'text-text-heading text-heading-small font-weight-heading-default leading-heading-small tracking--05 py-100 mb-200'
      : 'text-text-body text-body-medium font-weight-body-default leading-body-medium tracking-default py-100';
  }

  render() {
    return (
      <section role="group" id={this._internalId} aria-label={this.a11yLabel} class="flex flex-col gap-100">
        {this._hasLabelSlot && (
          <div class={this._labelClass}>
            <slot name="label" onSlotchange={this._updateSlots}></slot>
          </div>
        )}

        {/* list of secondary nav items */}
        <div class="flex flex-col gap-100">
          <slot />
        </div>
      </section>
    );
  }
}
